    for ridx in range(nlen-1,-1,-1):
        xv[ridx] = aug[ridx][nlen]
        for j in range(ridx+1,nlen): xv[ridx] -= aug[ridx][j]*xv[j]
        if abs(aug[ridx][ridx]) > 1e-12: xv[ridx] /= aug[ridx][ridx]
