                for rr in r_list:
                    fx = INV_FIXED[rr].get((ii,nn),0); pr = INV_PROP[rr].get((ii,nn),0)
                    aic[(ii,nn,rr)] = (fx/(CLEV*xone[ii]) + pr) if xone[ii] != 0 else pr
    ar = {rr: sum(aic.get((ii,nn,rr),0)*xone[ii] for ii in i_list for nn in n_list if (ii,nn) in inset) for rr in r_list}
